using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    private static List<OrderItem> CreateSampleItems(int count = 1) =>
        Enumerable.Range(1, count)
            .Select(i => new OrderItem
            {
                ProductName = $"Product {i}",
                Price = 10.00m * i,
                Quantity = i
            })
            .ToList();

    [TestMethod]
    public void CreateOrder_WithValidInput_ReturnsOrderWithCorrectProperties()
    {
        var items = CreateSampleItems();

        var order = _sut.CreateOrder("customer-1", items);

        Assert.IsNotNull(order);
        Assert.AreEqual("customer-1", order.CustomerId);
        Assert.AreSame(items, order.Items);
        Assert.IsFalse(string.IsNullOrEmpty(order.Id));
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_CalculatesTotalCorrectly()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 3 },
            new() { ProductName = "Gadget", Price = 12.50m, Quantity = 2 },
        };

        var order = _sut.CreateOrder("customer-1", items);

        // (5 * 3) + (12.50 * 2) = 15 + 25 = 40
        Assert.AreEqual(40.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentTime()
    {
        var before = DateTime.UtcNow;

        var order = _sut.CreateOrder("customer-1", CreateSampleItems());

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} should be between {before} and {after}.");
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder(null!, CreateSampleItems()));
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder("customer-1", null!));
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("customer-1", []));
    }

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsOrder()
    {
        var created = _sut.CreateOrder("customer-1", CreateSampleItems());

        var retrieved = _sut.GetOrder(created.Id);

        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyMatchingOrders()
    {
        _sut.CreateOrder("customer-A", CreateSampleItems());
        _sut.CreateOrder("customer-A", CreateSampleItems(2));
        _sut.CreateOrder("customer-B", CreateSampleItems());

        var orders = _sut.GetOrdersByCustomer("customer-A");

        Assert.AreEqual(2, orders.Count);
        Assert.IsTrue(orders.All(o => o.CustomerId == "customer-A"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoOrders_ReturnsEmptyList()
    {
        var orders = _sut.GetOrdersByCustomer("no-such-customer");

        Assert.AreEqual(0, orders.Count);
    }
}

